import{_ as e,o as t,c as n,ag as a}from"./chunks/framework.BPmc_f4o.js";const h=JSON.parse('{"title":"What is WordPress Application Layer?","description":"","frontmatter":{},"headers":[],"relativePath":"presentation.md","filePath":"presentation.md"}'),r={name:"presentation.md"};function o(i,s,p,l,d,c){return t(),n("div",null,[...s[0]||(s[0]=[a(`<h1 id="what-is-wordpress-application-layer" tabindex="-1">What is WordPress Application Layer? <a class="header-anchor" href="#what-is-wordpress-application-layer" aria-label="Permalink to &quot;What is WordPress Application Layer?&quot;">​</a></h1><p>WordPress Application Layer is a plugin that sits between the WordPress REST API and your client applications. It lets you control exactly what data is exposed, who can access it, how it is shaped, and at what rate — without touching WordPress core or your theme.</p><p>Beyond REST API responses, the plugin can <strong>drive your front-end entirely through webhooks</strong>: WordPress events (post publish, user register, WooCommerce order, custom CRON…) push data to your application in real time using the same schema as the REST API. You can combine both approaches or rely solely on webhooks to feed your application.</p><p>It is designed for:</p><ul><li><strong>Headless WordPress</strong> architectures (Next.js, Nuxt, SvelteKit, React, Vue, mobile apps)</li><li><strong>Multi-application</strong> setups where multiple clients share one WordPress back-end</li><li><strong>Event-driven</strong> architectures fed by webhooks instead of, or alongside, pull-based REST calls</li><li>Any site that needs <strong>security hardening</strong> at the REST API layer</li></ul><hr><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><p>The plugin operates exclusively within REST API contexts. Admin-authenticated requests are forwarded untouched, so it never interferes with the WordPress admin or other plugins.</p><p><strong>REST API request pipeline:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Incoming REST request</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       ▼</span></span>
<span class="line"><span>┌─────────────────────────┐</span></span>
<span class="line"><span>│  Application Matching   │  ← Which application owns this request? (Pro)</span></span>
<span class="line"><span>└────────────┬────────────┘</span></span>
<span class="line"><span>             │</span></span>
<span class="line"><span>┌────────────▼────────────┐</span></span>
<span class="line"><span>│  Authentication Check   │  ← JWT / WP App Passwords (OAuth: Pro)</span></span>
<span class="line"><span>└────────────┬────────────┘</span></span>
<span class="line"><span>             │</span></span>
<span class="line"><span>┌────────────▼────────────┐</span></span>
<span class="line"><span>│    IP / Rate Limiting   │  ← Per-user or global quotas, GeoIP blocking (Pro)</span></span>
<span class="line"><span>└────────────┬────────────┘</span></span>
<span class="line"><span>             │</span></span>
<span class="line"><span>┌────────────▼────────────┐</span></span>
<span class="line"><span>│    Routes Policy        │  ← Allowed methods, route-level rules (Pro)</span></span>
<span class="line"><span>└────────────┬────────────┘</span></span>
<span class="line"><span>             │</span></span>
<span class="line"><span>┌────────────▼────────────┐</span></span>
<span class="line"><span>│  WordPress REST API     │  ← Native WP handler</span></span>
<span class="line"><span>└────────────┬────────────┘</span></span>
<span class="line"><span>             │</span></span>
<span class="line"><span>┌────────────▼────────────┐</span></span>
<span class="line"><span>│  Property Transforms    │  ← Models: rename, remove, resolve, remap fields</span></span>
<span class="line"><span>└────────────┬────────────┘</span></span>
<span class="line"><span>             │</span></span>
<span class="line"><span>       REST Response</span></span></code></pre></div><p>Alongside this pipeline, <strong>webhooks and email notifications</strong> run independently of REST requests. Any WordPress event (post transitions, user actions, WooCommerce hooks, custom CRON, REST API hits) can trigger an outbound webhook and/or an email notification — scoped per application in Pro.</p><p><strong>Webhook / push pipeline:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WordPress Event (post publish, order created, cron, …)</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       ▼</span></span>
<span class="line"><span>┌─────────────────────────┐</span></span>
<span class="line"><span>│  Automation / Trigger   │  ← Conditions, chained actions (Pro)</span></span>
<span class="line"><span>└────────────┬────────────┘</span></span>
<span class="line"><span>             │</span></span>
<span class="line"><span>       ┌─────┴──────┐</span></span>
<span class="line"><span>       ▼            ▼</span></span>
<span class="line"><span>┌────────────┐  ┌────────────┐</span></span>
<span class="line"><span>│  Webhook   │  │   Email    │</span></span>
<span class="line"><span>│  (push)    │  │ Notification│</span></span>
<span class="line"><span>└────────────┘  └────────────┘</span></span></code></pre></div><hr><h2 id="free-features" tabindex="-1">Free Features <a class="header-anchor" href="#free-features" aria-label="Permalink to &quot;Free Features&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td><strong>Authentication</strong></td><td>WordPress Application Password (hardened to a single authorised user) and JWT. OAuth requires Pro</td></tr><tr><td><strong>Rate Limiting</strong></td><td>Global request quotas with configurable time windows</td></tr><tr><td><strong>IP Filtering</strong></td><td>Automatic and manual IP blacklisting. The plugin detects repeated violations and adds offenders automatically. IPv4 only — no CIDR, no country blocking. Read-only GeoIP stats available</td></tr><tr><td><strong>Routes</strong></td><td>Enforce auth and rate limiting globally. Disable the default <code>/users</code> routes to prevent user enumeration</td></tr><tr><td><strong>Properties &amp; Models</strong></td><td>Apply sitewide response transforms: resolve attachments, terms &amp; authors, flatten rendered fields, remove domain from URLs. Rules apply globally across all routes — individual property control (disable, rename, remap) requires Pro</td></tr><tr><td><strong>WordPress Security</strong></td><td>Disable XML-RPC, comments, RSS. Secure files, security headers</td></tr><tr><td><strong>Webhook</strong></td><td>Single outbound webhook with event triggers</td></tr><tr><td><strong>Hooks API</strong></td><td>Every option exposes a WordPress filter for customisation</td></tr></tbody></table><h2 id="pro-features" tabindex="-1">Pro Features <a class="header-anchor" href="#pro-features" aria-label="Permalink to &quot;Pro Features&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td><strong>Applications</strong></td><td>Isolate all settings per client — auth, routes, data, webhooks</td></tr><tr><td><strong>IP Filtering</strong></td><td>Both whitelist and blacklist modes. Whitelist mode restricts access to allowed origins only. Blacklist mode with configurable retention time. CIDR range support. Block or allow by country (GeoIP)</td></tr><tr><td><strong>Collections</strong></td><td>Enforce per-page limits and drag-and-drop sort order</td></tr><tr><td><strong>Routes Policy</strong></td><td>Per-route method control, user assignment, rate limiting and redirections. Safely disable any route with fine-grained per-application rules (avoids breaking unrelated plugin requests)</td></tr><tr><td><strong>Properties &amp; Models</strong></td><td>Disable, rename or remap any individual property. Remove empty properties to lighten responses. Build fully custom JSON schemas from scratch — map existing fields and add new static ones</td></tr><tr><td><strong>Automations</strong></td><td>Event-driven workflows with conditions and chained actions</td></tr><tr><td><strong>Multiple Webhooks</strong></td><td>Unlimited outbound webhooks, scoped per application</td></tr><tr><td><strong>Email Templates</strong></td><td>Transactional email templates with SMTP configuration, scoped per application</td></tr><tr><td><strong>Settings Route</strong></td><td>Schema editor for <code>/wp/v2/settings</code> — include ACF options pages and resolved WordPress menus, shaped with per-property control or custom schema</td></tr><tr><td><strong>Logs</strong></td><td>Full request history and audit trail</td></tr></tbody></table><hr><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><ul><li>WordPress 6.0+</li><li>PHP 7.4+</li></ul>`,21)])])}const g=e(r,[["render",o]]);export{h as __pageData,g as default};
